section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/flaky-test-elimination.json",
  "title": "Flaky Test Elimination",
  "type": "object",
  "required": [
    "artefact_id",
    "test_id",
    "classification",
    "root_cause",
    "fix_summary",
    "verification_runs",
    "verification_pass_count",
    "regression_test",
    "owner",
    "last_touched",
    "template_version",
    "status"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "test_id": {
      "type": "string",
      "minLength": 1
    },
    "classification": {
      "type": "string",
      "description": "one of: timing|ordering|state-leak|env-leak|non-determinism|infra|real-bug"
    },
    "root_cause": {
      "type": "string",
      "minLength": 1
    },
    "fix_summary": {
      "type": "string",
      "minLength": 1
    },
    "verification_runs": {
      "type": "integer",
      "minimum": 50
    },
    "verification_pass_count": {
      "type": "integer",
      "minimum": 50
    },
    "regression_test": {
      "type": "string",
      "minLength": 1,
      "description": "id/path of the regression test that catches re-occurrence"
    }
  },
  "additionalProperties": false
}
